// Pseudo in-sidecar router
function route(req){
  const tenant = req.headers['X-TENANT-ID'];
  const pri = req.headers['X-TENANT-PRIORITY'] || 'normal';
  const pathHash = hash(req.path);
  if(pri === 'high') return forwardFast(req);
  const key = `tenant:${tenant}:path:${pathHash}`;
  if(redis.incr(key) > RATE_LIMIT){
    return reject(429, 'Too many requests');
  }
  redis.pexpire(key, 60000);
  return forwardSlow(req);
}
```

