Design a sidecar container that reads the `X-TENANT-ID` header, loads the corresponding JSON schema from a ConfigMap mounted at `/etc/cnf/schemas/`, and validates incoming requests using Ajv before forwarding to the upstream service. Return HTTP 400 on validation failure with error details; return HTTP 200 and proxy the request on success.

**sidecar/validator.js**
```javascript
const Ajv = require('ajv');
const http = require('http');
const fs = require('fs');
const path = require('path');

const ajv = new Ajv({ allErrors: true });
const schemas = {};

function loadSchemas() {
  const schemaDir = '/etc/cnf/schemas/';
  fs.readdirSync(schemaDir).forEach(file => {
    if (file.endsWith('.json')) {
      const tenant = file.replace('.json', '');
      schemas[tenant] = JSON.parse(fs.readFileSync(path.join(schemaDir, file), 'utf8'));
    }
  });
}

function validateRequest(req, res) {
  let body = '';
  req.on('data', chunk => body += chunk);
  req.on('end', () => {
    const tenant = req.headers['x-tenant-id'];
    if (!tenant || !schemas[tenant]) {
      res.writeHead(400, { 'Content-Type': 'application/json' });
      res.end(JSON.stringify({ error: 'Invalid or missing tenant ID' }));
      return;
    }

    try {
      const data = JSON.parse(body);
      const valid = ajv.validate(schemas[tenant], data);
      if (!valid) {
        res.writeHead(400, { 'Content-Type': 'application/json' });
        res.end(JSON.stringify({ errors: ajv.errors }));
        return;
      }

      const proxyReq = http.request({
        hostname: 'localhost',
        port: 8080,
        path: '/',
        method: 'POST',
        headers: req.headers
      }, proxyRes => {
        res.writeHead(proxyRes.statusCode, proxyRes.headers);
        proxyRes.pipe(res);
      });
      proxyReq.write(body);
      proxyReq.end();
    } catch (e) {
      res.writeHead(400, { 'Content-Type': 'application/json' });
      res.end(JSON.stringify({ error: 'Invalid JSON body' }));
    }
  });
}

loadSchemas();
http.createServer(validateRequest).listen(8081);
```

**namespace.yaml**
