apiVersion: v1
kind: Namespace
metadata:
  name: cnf-gateway
---
apiVersion: v1
kind: ConfigMap
metadata:
  name: cnf-schemas
  namespace: cnf-gateway
data:
  tenant-a.json: |
    {
      "type": "object",
      "properties": {
        "orderId": { "type": "string" },
        "amount": { "type": "number", "minimum": 0 }
      },
      "required": ["orderId", "amount"]
    }
  tenant-b.json: |
    {
      "type": "object",
      "properties": {
        "userId": { "type": "string" },
        "email": { "type": "string", "format": "email" }
      },
      "required": ["userId"]
    }
---
apiVersion: v1
kind: Pod
metadata:
  name: api-gateway
  namespace: cnf-gateway
spec:
  containers:
  - name: main
    image: nginx:1.25
    ports:
    - containerPort: 80
  - name: validator
    image: node:20
    ports:
    - containerPort: 8081
    command: ["node", "/app/validator.js"]
    volumeMounts:
    - name: schemas
      mountPath: /etc/cnf/schemas
    - name: app
      mountPath: /app
  volumes:
  - name: schemas
    configMap:
      name: cnf-schemas
  - name: app
    emptyDir: {}
```

