class Breaker {
  constructor() { this.map = new Map(); }
  allow(tenant) {
    const s = this.map.get(tenant) || {f:0, t:0, open:0};
    const now = Date.now();
    if (now < s.open) return false;
    if (now - s.t > 60000) { s.f = 0; s.t = now; }
    const ok = s.f < 5;
    if (!ok) s.open = now + 30000;
    this.map.set(tenant, s);
    return ok;
  }
  fail(tenant) {
    const s = this.map.get(tenant) || {f:0, t:Date.now(), open:0};
    s.f += 1; s.t = Date.now(); this.map.set(tenant, s);
  }
}
```

