// Admission webhook validating signed plugin images per tenant
package main

func validatePluginImage(imageRef, tenantNamespace string) error {
    // Verify Cosign signature using KMS public key
    if !cosign.Verify(imageRef, kmsPublicKey) {
        return fmt.Errorf("unsigned plugin image: %s", imageRef)
    }

    // Validate SBOM presence and integrity
    if !sbom.Validate(imageRef) {
        return fmt.Errorf("missing or invalid SBOM for: %s", imageRef)
    }

    // Check against tenant-specific allowlist
    if !allowlist.Contains(tenantNamespace, imageRef) {
        return fmt.Errorf("plugin not in tenant allowlist: %s", imageRef)
    }
    return nil
}
```

